/**
 * FrameStudio.jsx — Complete React Component with 6 real PNG frame sets
 * ─────────────────────────────────────────────────────────────────────
 * No external assets needed — all frame images are embedded as base64.
 * Just drop this file into your React project and import it.
 *
 * Usage:
 *   import FrameStudio from './FrameStudio';
 *   export default function App() { return <FrameStudio />; }
 *
 * 8-PIECE FRAME GRID:
 *  ┌──────────┬──────────────────────┬──────────┐
 *  │ cornerTL │   topTile  →→→→      │ cornerTR │  ← corners: NEVER scale
 *  ├──────────┼──────────────────────┼──────────┤
 *  │ leftTile │  painting + mat      │rightTile │  ← sides: stretch 1 axis
 *  ├──────────┼──────────────────────┼──────────┤
 *  │ cornerBL │  bottomTile →→→→     │ cornerBR │
 *  └──────────┴──────────────────────┴──────────┘
 */

